'use client';

import { useState, useEffect } from 'react';
import { ResizeBlock, P3OutputSize, SizePreset } from '../lib/types';
import ResizeBlockCard from './ResizeBlockCard';
import { Download, Plus, RefreshCw, Box, Save, PlusCircle, Edit2, Globe } from 'lucide-react';
import { resizeImageAdvanced } from '../lib/imageUtils';
import { generateZip } from '../lib/zipUtils';
import { fetchBlockPresets, saveBlockPreset, updateBlockPreset } from '../lib/blockPresetService';

export default function BlockResizeTab() {
    const [prefix, setPrefix] = useState('');
    const [blocks, setBlocks] = useState<ResizeBlock[]>([{
        id: crypto.randomUUID(),
        outputs: [],
        fitMode: 'contain_with_background',
        align: 'center',
        bgColor: '#ffffff'
    }]);
    const [isProcessing, setIsProcessing] = useState(false);

    // Preset Library State
    const [presets, setPresets] = useState<SizePreset[]>([]);
    const [isLoadingPresets, setIsLoadingPresets] = useState(false);
    const [focusedBlockId, setFocusedBlockId] = useState<string | null>(blocks[0].id);

    // New Preset Form State
    const [showNewPresetForm, setShowNewPresetForm] = useState(false);
    const [newPresetName, setNewPresetName] = useState('');
    const [newPresetAuthor, setNewPresetAuthor] = useState('');
    const [newPresetSizes, setNewPresetSizes] = useState<P3OutputSize[]>([]);
    const [newW, setNewW] = useState('');
    const [newH, setNewH] = useState('');
    const [isSavingPreset, setIsSavingPreset] = useState(false);
    const [editingPresetId, setEditingPresetId] = useState<string | null>(null);

    useEffect(() => {
        loadPresets();
    }, []);

    const loadPresets = async () => {
        setIsLoadingPresets(true);
        try {
            const fetched = await fetchBlockPresets();
            setPresets(fetched);
        } catch (e) {
            console.error("Failed to load block presets", e);
        } finally {
            setIsLoadingPresets(false);
        }
    };

    // --- Block Management ---

    const handleAddBlock = () => {
        const newId = crypto.randomUUID();
        setBlocks([...blocks, {
            id: newId,
            outputs: [],
            fitMode: 'contain_with_background',
            align: 'center',
            bgColor: '#ffffff'
        }]);
        setFocusedBlockId(newId);
    };

    const handleUpdateBlock = (id: string, updates: Partial<ResizeBlock>) => {
        setBlocks(blocks.map(b => b.id === id ? { ...b, ...updates } : b));
    };

    const handleRemoveBlock = (id: string) => {
        const newBlocks = blocks.filter(b => b.id !== id);
        setBlocks(newBlocks);
        if (focusedBlockId === id) {
            setFocusedBlockId(newBlocks.length > 0 ? newBlocks[0].id : null);
        }
    };

    // --- Preset Creation ---

    const addSizeToNewPreset = () => {
        const w = parseInt(newW);
        const h = parseInt(newH);
        if (!w || !h) return;
        setNewPresetSizes([...newPresetSizes, { width: w, height: h }]);
        setNewW('');
        setNewH('');
    };

    const removeSizeFromNewPreset = (idx: number) => {
        const newSizes = [...newPresetSizes];
        newSizes.splice(idx, 1);
        setNewPresetSizes(newSizes);
    };

    const handleSaveNewPreset = async () => {
        if (!newPresetName || !newPresetAuthor || newPresetSizes.length === 0) return;

        setIsSavingPreset(true);
        try {
            if (editingPresetId) {
                await updateBlockPreset(editingPresetId, newPresetName, newPresetAuthor, newPresetSizes);
            } else {
                await saveBlockPreset(newPresetName, newPresetAuthor, newPresetSizes);
            }
            setShowNewPresetForm(false);
            setNewPresetName('');
            setNewPresetAuthor('');
            setNewPresetSizes([]);
            setEditingPresetId(null);
            await loadPresets();
        } catch (e) {
            alert("Error saving preset");
        } finally {
            setIsSavingPreset(false);
        }
    };

    const handleEditPreset = (preset: SizePreset) => {
        setEditingPresetId(preset.id);
        setNewPresetName(preset.name);
        setNewPresetAuthor(preset.authorName || '');
        setNewPresetSizes([...preset.sizes]);
        setShowNewPresetForm(true);
    };


    // --- Generation ---

    const canGenerate = blocks.some(b => b.inputImage && b.outputs.length > 0);

    const handleGenerate = async () => {
        if (!canGenerate) return;
        setIsProcessing(true);

        try {
            const zipFiles: { name: string; blob: Blob }[] = [];

            for (const block of blocks) {
                if (!block.inputImage || block.outputs.length === 0) continue;

                for (const output of block.outputs) {
                    const blob = await resizeImageAdvanced(
                        block.inputImage,
                        output.width,
                        output.height,
                        block.fitMode,
                        block.align,
                        block.bgColor
                    );

                    // Name format: [prefix]_[width]x[height].[ext]
                    const ext = block.inputImage.name.substring(block.inputImage.name.lastIndexOf('.')) || '.jpg';
                    const newName = prefix
                        ? `${prefix}_${output.width}x${output.height}${ext}`
                        : `${output.width}x${output.height}${ext}`;

                    // Prevent duplicate names in zip if same size requested multiple times or across blocks with same prefix
                    const uniqueName = zipFiles.some(f => f.name === newName) 
                        ? newName.replace(ext, `_${block.id.substring(0,4)}${ext}`)
                        : newName;

                    zipFiles.push({ name: uniqueName, blob });
                }
            }

            if (zipFiles.length > 0) {
                const zipFilename = `block_resize_${Date.now()}.zip`;
                await generateZip(zipFiles, zipFilename);
            } else {
                alert("Không có ảnh nào hợp lệ để xuất.");
            }
        } catch (e) {
            console.error(e);
            alert("Lỗi quá trình xử lý ảnh!");
        } finally {
            setIsProcessing(false);
        }
    };

    return (
        <div className="flex flex-col gap-8 animate-in fade-in zoom-in-95 duration-300">
            {/* Top Area: Session Config & Preset Library */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

                {/* Prefix */}
                <div className="lg:col-span-1 glass-card rounded-2xl p-6 flex flex-col justify-center h-full">
                    <label className="block text-sm font-medium text-zinc-300 mb-2 flex items-center gap-2">
                        <Box className="w-4 h-4 text-blue-400" />
                        Tiền tố (Prefix) chung
                    </label>
                    <input
                        type="text"
                        value={prefix}
                        onChange={(e) => setPrefix(e.target.value)}
                        placeholder="VD: BANNER_SALE"
                        className="w-full bg-zinc-900/50 border border-zinc-700/50 rounded-xl px-4 py-3 text-zinc-100 placeholder:text-zinc-600 focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all font-mono"
                    />
                     <p className="text-xs text-zinc-500 mt-2">
                            Tên mẫu: <span className="text-blue-400 font-mono">[Prefix]_{"{rộng}x{cao}"}.jpg</span>
                    </p>
                </div>

                {/* Preset Library / Form */}
                <div className="lg:col-span-2 glass-card rounded-2xl p-6 border-t-4 border-purple-500 flex flex-col justify-center">
                    <div className="flex justify-between items-center mb-4">
                        <h3 className="text-lg font-bold text-zinc-100 flex items-center gap-2">
                             Công Cụ Hỗ Trợ
                        </h3>
                        {!showNewPresetForm && (
                            <button 
                                onClick={() => setShowNewPresetForm(true)}
                                className="text-sm px-3 py-1.5 bg-purple-600/20 text-purple-400 hover:bg-purple-600/30 rounded-lg font-medium transition-colors border border-purple-500/30 flex items-center gap-1.5"
                            >
                                <PlusCircle className="w-4 h-4" /> Tạo Preset Mới
                            </button>
                        )}
                    </div>

                    {showNewPresetForm ? (
                        <div className="bg-black/30 p-4 rounded-xl border border-zinc-800 space-y-4 animate-in slide-in-from-top-2">
                            <h4 className="font-semibold text-purple-300 text-sm">
                                {editingPresetId ? 'Sửa thông tin Preset' : 'Thông tin Preset Kích Thước'}
                            </h4>
                            <div className="grid grid-cols-2 gap-3">
                                <input type="text" placeholder="Tên chức năng (VD: Facebook Pack)" value={newPresetName} onChange={e => setNewPresetName(e.target.value)} className="bg-zinc-900 border border-zinc-700 rounded-lg px-3 py-1.5 text-sm" />
                                <input type="text" placeholder="Tác giả" value={newPresetAuthor} onChange={e => setNewPresetAuthor(e.target.value)} className="bg-zinc-900 border border-zinc-700 rounded-lg px-3 py-1.5 text-sm" />
                            </div>

                            <div className="p-3 bg-zinc-900/50 rounded-lg border border-zinc-800">
                                <span className="text-xs text-zinc-500 block mb-2">Các kích thước:</span>
                                <div className="flex flex-wrap gap-2 mb-3">
                                    {newPresetSizes.map((sz, i) => (
                                        <div key={i} className="bg-zinc-800 px-2 py-1 rounded text-xs font-mono text-zinc-300 flex items-center gap-1 border border-zinc-700">
                                            {sz.width}×{sz.height}
                                            <button onClick={() => removeSizeFromNewPreset(i)} className="text-zinc-500 hover:text-red-400 ml-1">×</button>
                                        </div>
                                    ))}
                                    {newPresetSizes.length === 0 && <span className="text-xs text-zinc-600 italic">Chưa có kích thước nào</span>}
                                </div>
                                <div className="flex items-center gap-2">
                                    <input type="number" placeholder="W" value={newW} onChange={e => setNewW(e.target.value)} onKeyDown={e => e.key === 'Enter' && addSizeToNewPreset()} className="w-20 bg-black border border-zinc-700 rounded px-2 py-1 text-xs" />
                                    <span className="text-zinc-500">×</span>
                                    <input type="number" placeholder="H" value={newH} onChange={e => setNewH(e.target.value)} onKeyDown={e => e.key === 'Enter' && addSizeToNewPreset()} className="w-20 bg-black border border-zinc-700 rounded px-2 py-1 text-xs" />
                                    <button onClick={addSizeToNewPreset} className="bg-zinc-800 px-3 py-1 rounded text-xs hover:bg-zinc-700">Thêm</button>
                                </div>
                            </div>

                            <div className="flex gap-2 justify-end mt-4">
                                <button onClick={() => {
                                    setShowNewPresetForm(false);
                                    setEditingPresetId(null);
                                    setNewPresetName('');
                                    setNewPresetAuthor('');
                                    setNewPresetSizes([]);
                                }} className="px-4 py-1.5 rounded-lg text-sm bg-zinc-800 hover:bg-zinc-700">Đóng</button>
                                <button 
                                    onClick={handleSaveNewPreset} 
                                    disabled={!newPresetName || !newPresetAuthor || newPresetSizes.length === 0 || isSavingPreset}
                                    className="px-4 py-1.5 rounded-lg text-sm bg-purple-600 hover:bg-purple-500 text-white font-medium disabled:opacity-50"
                                >
                                    {isSavingPreset ? 'Đang lưu...' : (editingPresetId ? 'Cập Nhật Preset' : 'Lưu Public Preset')}
                                </button>
                            </div>
                        </div>
                    ) : (
                        <div className="flex flex-col gap-3">
                            <div className="text-sm text-zinc-400">
                                Preset giúp lưu nhanh nhiều kích thước đầu ra để sử dụng lại cho các Job sau. Preset được chia sẻ chung cho mọi người. 
                                Hãy chọn Preset tương ứng ở dropdown <span className="text-zinc-300 font-bold">"Load từ Preset"</span> bên trong từng thẻ Block bên dưới!
                            </div>

                            <div className="flex gap-3 overflow-x-auto pb-2 custom-scrollbar">
                                {isLoadingPresets ? (
                                    <div className="text-sm text-zinc-500 italic p-4">Đang tải...</div>
                                ) : presets.length === 0 ? (
                                    <div className="text-sm text-zinc-500 italic p-4">Chưa có preset public nào. Hãy tạo mới!</div>
                                ) : (
                                    presets.map(p => (
                                        <div
                                            key={p.id}
                                            className="shrink-0 bg-zinc-900 border border-zinc-800 rounded-xl p-3 text-left min-w-[200px] flex flex-col group relative"
                                        >
                                            <div className="flex items-center justify-between mb-1">
                                                <span className="font-medium text-sm text-zinc-200">{p.name}</span>
                                                <Globe className="w-3 h-3 text-zinc-600" />
                                            </div>
                                            <span className="text-xs text-zinc-500 mb-2">bởi {p.authorName}</span>
                                            <div className="flex flex-wrap gap-1 mt-auto">
                                                {p.sizes.slice(0, 3).map((sz, i) => (
                                                    <span key={i} className="text-[10px] bg-black/50 border border-zinc-800 px-1.5 py-0.5 rounded font-mono text-zinc-400">
                                                        {sz.width}x{sz.height}
                                                    </span>
                                                ))}
                                                {p.sizes.length > 3 && (
                                                    <span className="text-[10px] bg-zinc-800 px-1.5 py-0.5 rounded text-zinc-500">+{p.sizes.length - 3}</span>
                                                )}
                                            </div>

                                            <button 
                                                onClick={() => handleEditPreset(p)}
                                                className="absolute top-2 right-2 p-1 bg-purple-500/80 text-white rounded text-xs opacity-0 group-hover:opacity-100 transition-opacity z-10 hover:bg-purple-600"
                                                title="Sửa preset"    
                                            >
                                                <Edit2 className="w-3 h-3" />
                                            </button>
                                        </div>
                                    ))
                                )}
                            </div>
                        </div>
                    )}
                </div>
            </div>

            {/* Blocks List */}
            <div className="space-y-6">
                {blocks.map((block, i) => (
                    <div 
                        key={block.id} 
                        onClick={() => setFocusedBlockId(block.id)}
                        className={`transition-all rounded-2xl ${focusedBlockId === block.id ? 'ring-2 ring-purple-500 shadow-[0_0_15px_rgba(168,85,247,0.15)] bg-purple-900/5' : 'hover:bg-white/5 opacity-80'}`}
                    >
                         <ResizeBlockCard
                            index={i}
                            block={block}
                            onChange={handleUpdateBlock}
                            onRemove={handleRemoveBlock}
                            isFocused={focusedBlockId === block.id}
                            presets={presets}
                        />
                    </div>
                ))}
            </div>

            {/* Actions Footer */}
            <div className="flex flex-col md:flex-row gap-4 justify-between items-center sticky bottom-6 z-20">
                <button
                    onClick={handleAddBlock}
                    className="w-full md:w-auto px-6 py-4 bg-zinc-800 hover:bg-zinc-700 text-zinc-200 rounded-2xl border border-zinc-700 transition-colors font-bold flex items-center justify-center gap-2 shadow-lg"
                >
                    <Plus className="w-5 h-5 text-zinc-400" />
                    Thêm Block Mới
                </button>

                <button
                    onClick={handleGenerate}
                    disabled={!canGenerate || isProcessing}
                    className="w-full md:flex-1 max-w-md glass-card p-4 rounded-2xl flex items-center justify-center gap-3 text-lg font-bold disabled:opacity-50 disabled:cursor-not-allowed hover:bg-blue-600/20 hover:border-blue-500/50 transition-all border border-zinc-700 shadow-xl shadow-blue-900/10 group"
                >
                    {isProcessing ? (
                        <RefreshCw className="w-6 h-6 animate-spin text-blue-400" />
                    ) : (
                        <Download className="w-6 h-6 text-blue-400 group-hover:scale-110 transition-transform" />
                    )}
                    <span>{isProcessing ? 'Đang xử lý...' : 'Generate Tất Cả (ZIP)'}</span>
                </button>
            </div>

            {!canGenerate && blocks.length > 0 && (
                <div className="text-center text-sm text-zinc-500 pb-8">
                    * Vui lòng thêm ít nhất 1 ảnh và 1 kích thước đầu ra để có thể xuất file.
                </div>
            )}
        </div>
    );
}

'use client';

import { useState, useRef, ChangeEvent, useCallback, useMemo } from 'react';
import { Upload, Download, RefreshCw, X, Image as ImageIcon, Ruler } from 'lucide-react';
import { readImageDimensions, resizeImage } from '../lib/imageUtils';
import { parseResizePercentInput } from '../lib/validationUtils';
import { generateZip } from '../lib/zipUtils';
import { normalizeRatioLabel } from '../lib/ratioUtils';

interface DimensionEntry {
    width: string;
    height: string;
}

export default function FreeResizeTab() {
    const [file, setFile] = useState<File | null>(null);
    const [previewUrl, setPreviewUrl] = useState<string | null>(null);
    const [originalDim, setOriginalDim] = useState<{ width: number; height: number } | null>(null);
    const [percentInput, setPercentInput] = useState<string>('100');
    const [isProcessing, setIsProcessing] = useState(false);
    const [prefix, setPrefix] = useState('');
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Dimension-based resize state
    const [dimEntries, setDimEntries] = useState<DimensionEntry[]>([{ width: '', height: '' }]);
    const [dimError, setDimError] = useState<string | null>(null);

    // Whether the last edit came from % or dimension inputs (to avoid infinite sync loops)
    const [lastEditSource, setLastEditSource] = useState<'percent' | 'dimension' | null>(null);

    // Compute original ratio label
    const originalRatioLabel = useMemo(() => {
        if (!originalDim) return '';
        return normalizeRatioLabel(originalDim.width, originalDim.height);
    }, [originalDim]);

    const originalRatioNum = useMemo(() => {
        if (!originalDim || originalDim.height === 0) return 1;
        return originalDim.width / originalDim.height;
    }, [originalDim]);

    const handleFileChange = async (e: ChangeEvent<HTMLInputElement>) => {
        const selected = e.target.files?.[0];
        if (!selected) return;

        try {
            const dims = await readImageDimensions(selected);
            setFile(selected);
            setOriginalDim(dims);

            if (previewUrl) URL.revokeObjectURL(previewUrl);
            setPreviewUrl(URL.createObjectURL(selected));

            // Reset
            setDimEntries([{ width: '', height: '' }]);
            setDimError(null);
        } catch (err) {
            alert('Không thể đọc ảnh này. Vui lòng chọn file hợp lệ.');
        }
    };

    const clearFile = () => {
        setFile(null);
        setOriginalDim(null);
        if (previewUrl) URL.revokeObjectURL(previewUrl);
        setPreviewUrl(null);
        if (fileInputRef.current) fileInputRef.current.value = '';
        setDimEntries([{ width: '', height: '' }]);
        setDimError(null);
    };

    // --- Sync: % -> dimensions ---
    const handlePercentChange = (value: string) => {
        setPercentInput(value);
        setLastEditSource('percent');

        if (!originalDim) return;
        const pcts = parseResizePercentInput(value);
        if (pcts.length > 0) {
            const newEntries = pcts.map(pct => ({
                width: String(Math.round((originalDim.width * pct) / 100)),
                height: String(Math.round((originalDim.height * pct) / 100)),
            }));
            setDimEntries(newEntries);
            setDimError(null);
        }
    };

    // --- Sync: dimension -> % ---
    const handleDimWidthChange = (index: number, widthStr: string) => {
        setLastEditSource('dimension');
        const newEntries = [...dimEntries];
        newEntries[index] = { ...newEntries[index], width: widthStr };

        // Auto-calculate height from width
        const w = parseFloat(widthStr);
        if (originalDim && !isNaN(w) && w > 0) {
            const h = Math.round(w / originalRatioNum);
            newEntries[index].height = String(h);

            // Sync back to %
            const pct = (w / originalDim.width) * 100;
            syncPercentsFromEntries(newEntries);
            setDimError(null);
        }

        setDimEntries(newEntries);
    };

    const handleDimHeightChange = (index: number, heightStr: string) => {
        setLastEditSource('dimension');
        const newEntries = [...dimEntries];
        newEntries[index] = { ...newEntries[index], height: heightStr };

        // Auto-calculate width from height
        const h = parseFloat(heightStr);
        if (originalDim && !isNaN(h) && h > 0) {
            const w = Math.round(h * originalRatioNum);
            newEntries[index].width = String(w);

            syncPercentsFromEntries(newEntries);
            setDimError(null);
        }

        setDimEntries(newEntries);
    };

    const syncPercentsFromEntries = (entries: DimensionEntry[]) => {
        if (!originalDim) return;
        const pcts = entries
            .map(e => {
                const w = parseFloat(e.width);
                if (isNaN(w) || w <= 0) return null;
                return Math.round((w / originalDim.width) * 10000) / 100; // 2 decimal places
            })
            .filter(v => v !== null) as number[];

        if (pcts.length > 0) {
            setPercentInput(pcts.join(', '));
        }
    };

    const addDimEntry = () => {
        setDimEntries([...dimEntries, { width: '', height: '' }]);
    };

    const removeDimEntry = (index: number) => {
        const newEntries = dimEntries.filter((_, i) => i !== index);
        if (newEntries.length === 0) {
            setDimEntries([{ width: '', height: '' }]);
        } else {
            setDimEntries(newEntries);
        }
        syncPercentsFromEntries(newEntries.length > 0 ? newEntries : []);
    };

    const percents = parseResizePercentInput(percentInput);

    const handleGenerate = async () => {
        if (!file || !originalDim || percents.length === 0) return;

        setIsProcessing(true);
        try {
            const jobs = percents.map(async (pct) => {
                const w = Math.round((originalDim.width * pct) / 100);
                const h = Math.round((originalDim.height * pct) / 100);
                const blob = await resizeImage(file, w, h);

                // Naming: [prefix]_[width]x[height].[ext]
                const ext = file.name.substring(file.name.lastIndexOf('.')) || '.jpg';
                const newName = prefix
                    ? `${prefix}_${w}x${h}${ext}`
                    : `${w}x${h}${ext}`;

                return { name: newName, blob, url: URL.createObjectURL(blob) };
            });

            const results = await Promise.all(jobs);

            if (results.length === 1) {
                const a = document.createElement('a');
                a.href = results[0].url;
                a.download = results[0].name;
                a.click();
            } else {
                const zipFiles = results.map(r => ({ name: r.name, blob: r.blob }));
                await generateZip(zipFiles, `free_resize_${Date.now()}.zip`);
            }

            results.forEach(r => URL.revokeObjectURL(r.url));
        } catch (err) {
            console.error(err);
            alert('Có lỗi xảy ra khi xử lý ảnh.');
        } finally {
            setIsProcessing(false);
        }
    };

    return (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            {/* Upload Column */}
            <div className="glass-card rounded-2xl p-6 lg:p-8 flex flex-col items-center justify-center min-h-[400px]">
                {!file ? (
                    <div
                        onClick={() => fileInputRef.current?.click()}
                        className="w-full flex-1 border-2 border-dashed border-zinc-700/50 hover:border-blue-500/50 transition-colors rounded-xl flex flex-col items-center justify-center gap-4 cursor-pointer text-zinc-400 hover:text-zinc-200 bg-white/5 hover:bg-white/10"
                    >
                        <Upload className="w-10 h-10 mb-2 opacity-80" />
                        <p className="font-medium text-lg text-center">Tải ảnh lên để bắt đầu</p>
                        <p className="text-sm opacity-60">Kéo thả hoặc click vào đây</p>
                        <input
                            ref={fileInputRef}
                            type="file"
                            accept="image/*"
                            className="hidden"
                            onChange={handleFileChange}
                        />
                    </div>
                ) : (
                    <div className="w-full h-full flex flex-col group relative">
                        <div className="absolute top-4 right-4 z-10 flex gap-2">
                            <button onClick={clearFile} className="bg-black/50 hover:bg-red-500/80 backdrop-blur p-2 rounded-full transition-colors" title="Xóa ảnh">
                                <X className="w-5 h-5 text-white" />
                            </button>
                        </div>
                        <div className="flex-1 min-h-[300px] relative rounded-xl overflow-hidden bg-black/40 flex items-center justify-center p-4 border border-zinc-800">
                            {/* eslint-disable-next-line @next/next/no-img-element */}
                            <img src={previewUrl!} alt="Preview" className="max-w-full max-h-full object-contain rounded drop-shadow-lg" />
                        </div>
                        <div className="mt-4 p-4 rounded-xl bg-white/5 border border-white/10 flex items-center justify-between">
                            <div className="flex items-center gap-3 overflow-hidden">
                                <div className="p-2 bg-blue-500/20 rounded-lg text-blue-400">
                                    <ImageIcon className="w-5 h-5" />
                                </div>
                                <div className="truncate">
                                    <p className="font-medium truncate text-sm">{file.name}</p>
                                    <p className="text-xs text-zinc-400">{originalDim?.width} x {originalDim?.height} px</p>
                                </div>
                            </div>
                            {originalDim && (
                                <div className="flex items-center gap-2 bg-purple-500/15 border border-purple-500/30 px-3 py-1.5 rounded-lg">
                                    <Ruler className="w-4 h-4 text-purple-400" />
                                    <span className="text-sm font-mono text-purple-300">
                                        Original ratio: {originalRatioLabel}
                                    </span>
                                </div>
                            )}
                        </div>
                    </div>
                )}
            </div>

            {/* Settings Column */}
            <div className="flex flex-col gap-6">
                <div className="glass-card rounded-2xl p-6 lg:p-8">
                    <h2 className="text-xl font-bold mb-6 text-zinc-100">Thông số Resize</h2>

                    <div className="space-y-5">
                        {/* Prefix */}
                        <div>
                            <label className="block text-sm font-medium text-zinc-300 mb-2">
                                Prefix tên file đầu ra (tuỳ chọn)
                            </label>
                            <input
                                type="text"
                                value={prefix}
                                onChange={(e) => setPrefix(e.target.value)}
                                placeholder="VD: VTS (để trống nếu không cần)"
                                className="w-full bg-zinc-900/50 border border-zinc-700/50 rounded-xl px-4 py-3 text-zinc-100 placeholder:text-zinc-600 focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all font-mono"
                            />
                        </div>

                        {/* Percentage input */}
                        <div className="bg-white/5 border border-white/10 rounded-xl p-4">
                            <label className="block text-sm font-medium text-zinc-300 mb-2">
                                📐 Resize theo phần trăm (%)
                            </label>
                            <input
                                type="text"
                                value={percentInput}
                                onChange={(e) => handlePercentChange(e.target.value)}
                                placeholder="VD: 50, 75, 120"
                                className="w-full bg-zinc-900/50 border border-zinc-700/50 rounded-xl px-4 py-3 text-zinc-100 placeholder:text-zinc-600 focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all font-mono"
                            />
                            <p className="text-xs text-zinc-500 mt-2">
                                Nhập nhiều mức % cách nhau bằng dấu phẩy. Thay đổi ở đây sẽ tự động cập nhật ô kích thước bên dưới.
                            </p>
                        </div>

                        {/* Dimension-based input */}
                        <div className="bg-white/5 border border-white/10 rounded-xl p-4">
                            <label className="block text-sm font-medium text-zinc-300 mb-2">
                                📏 Resize theo kích thước mong muốn (px)
                            </label>
                            <div className="space-y-3">
                                {dimEntries.map((entry, i) => (
                                    <div key={i} className="flex items-center gap-2">
                                        <input
                                            type="number"
                                            placeholder="Width"
                                            value={entry.width}
                                            onChange={(e) => handleDimWidthChange(i, e.target.value)}
                                            className="flex-1 bg-zinc-900/50 border border-zinc-700/50 rounded-lg px-3 py-2.5 text-zinc-100 placeholder:text-zinc-600 focus:ring-2 focus:ring-blue-500/50 font-mono text-sm"
                                        />
                                        <span className="text-zinc-500 text-sm">×</span>
                                        <input
                                            type="number"
                                            placeholder="Height"
                                            value={entry.height}
                                            onChange={(e) => handleDimHeightChange(i, e.target.value)}
                                            className="flex-1 bg-zinc-900/50 border border-zinc-700/50 rounded-lg px-3 py-2.5 text-zinc-100 placeholder:text-zinc-600 focus:ring-2 focus:ring-blue-500/50 font-mono text-sm"
                                        />
                                        {dimEntries.length > 1 && (
                                            <button
                                                onClick={() => removeDimEntry(i)}
                                                className="p-2 text-zinc-500 hover:text-red-400 transition-colors"
                                            >
                                                <X className="w-4 h-4" />
                                            </button>
                                        )}
                                    </div>
                                ))}
                            </div>
                            <button
                                onClick={addDimEntry}
                                className="mt-3 text-sm text-blue-400 hover:text-blue-300 transition-colors font-medium"
                            >
                                + Thêm kích thước
                            </button>
                            <p className="text-xs text-zinc-500 mt-2">
                                Nhập Width hoặc Height, ô còn lại sẽ tự tính theo tỉ lệ gốc. Giá trị này đồng bộ với mức % bên trên.
                            </p>
                            {dimError && (
                                <p className="text-xs text-red-400 mt-2">{dimError}</p>
                            )}
                        </div>
                    </div>

                    {/* Preview */}
                    <div className="mt-8 border-t border-zinc-800 pt-6">
                        <h3 className="text-sm font-medium text-zinc-400 mb-4">Preview Kích thước Đầu ra</h3>
                        {percents.length > 0 && originalDim ? (
                            <ul className="space-y-2">
                                {percents.map((pct, i) => (
                                    <li key={i} className="flex justify-between items-center p-3 rounded-lg bg-zinc-900/40 border border-zinc-800">
                                        <span className="text-zinc-300 font-medium">{pct}%</span>
                                        <span className="text-blue-400 font-mono">
                                            {Math.round((originalDim.width * pct) / 100)} x {Math.round((originalDim.height * pct) / 100)} px
                                        </span>
                                    </li>
                                ))}
                            </ul>
                        ) : (
                            <p className="text-sm text-zinc-600 italic">Chưa có thông số hợp lệ</p>
                        )}
                    </div>
                </div>

                <button
                    onClick={handleGenerate}
                    disabled={!file || !originalDim || percents.length === 0 || isProcessing}
                    className="w-full glass-card p-6 rounded-2xl flex items-center justify-center gap-3 text-lg font-bold disabled:opacity-50 disabled:cursor-not-allowed hover:bg-blue-600/20 hover:border-blue-500/50 transition-all group"
                >
                    {isProcessing ? (
                        <RefreshCw className="w-6 h-6 animate-spin text-blue-400" />
                    ) : (
                        <Download className="w-6 h-6 text-blue-400 group-hover:scale-110 transition-transform" />
                    )}
                    <span>{isProcessing ? 'Đang xử lý...' : 'Generate & Download'}</span>
                </button>
            </div>
        </div>
    );
}

'use client';

import { useState, useMemo } from 'react';
import { Preset } from '../lib/types';
import PresetSelector from './PresetSelector';
import SourceUploadBlock from './SourceUploadBlock';
import OutputSizeList from './OutputSizeList';
import { readImageDimensions, resizeImage } from '../lib/imageUtils';
import { validateSourceUploads, canGenerateFullPack } from '../lib/validationUtils';
import { generateZip } from '../lib/zipUtils';
import { Download, RefreshCw, Eye } from 'lucide-react';
import PresetBuilder from './PresetBuilder';

export default function PresetResizeTab() {
    const [preset, setPreset] = useState<Preset | null>(null);
    const [uploads, setUploads] = useState<Record<string, { file: File; width: number; height: number }>>({});
    const [isProcessing, setIsProcessing] = useState(false);
    const [showBuilder, setShowBuilder] = useState(false);
    const [editingPreset, setEditingPreset] = useState<Preset | null>(null);
    const [prefix, setPrefix] = useState('');
    const [refreshKey, setRefreshKey] = useState(0);

    const handlePresetSelect = (selected: Preset) => {
        setPreset(selected);
        setUploads({}); // Reset when changing preset
    };

    const handleUpload = async (blockId: string, file: File) => {
        try {
            const dim = await readImageDimensions(file);
            setUploads(prev => ({
                ...prev,
                [blockId]: { file, width: dim.width, height: dim.height }
            }));
        } catch (e) {
            alert("Lỗi đọc ảnh");
        }
    };

    const handleRemove = (blockId: string) => {
        const newUploads = { ...uploads };
        delete newUploads[blockId];
        setUploads(newUploads);
    };

    // derived validation state
    const validation = useMemo(() => {
        if (!preset) return { isValid: false, errors: {} };
        return validateSourceUploads(preset, uploads);
    }, [preset, uploads]);

    const canGenerate = preset ? canGenerateFullPack(validation, preset, uploads) : false;

    const handleGenerate = async () => {
        if (!preset || !canGenerate) return;
        setIsProcessing(true);

        try {
            const zipFiles = [];

            // Process each output size
            for (const output of preset.outputs) {
                const sourceData = uploads[output.sourceBlockId];
                if (!sourceData) continue; // Should not happen if validation passed

                const blob = await resizeImage(sourceData.file, output.width, output.height);

                // Naming: [prefix]_[width]x[height].[ext]
                const origFile = sourceData.file;
                const ext = origFile.name.substring(origFile.name.lastIndexOf('.')) || '.jpg';
                const newName = prefix
                    ? `${prefix}_${output.width}x${output.height}${ext}`
                    : `${output.width}x${output.height}${ext}`;

                zipFiles.push({ name: newName, blob });
            }

            const zipFilename = `${preset.id}_pack_${Date.now()}.zip`;
            await generateZip(zipFiles, zipFilename);

        } catch (e) {
            console.error(e);
            alert("Lỗi khi xử lý ảnh");
        } finally {
            setIsProcessing(false);
        }
    };

    const handleBuilderDone = () => {
        setShowBuilder(false);
        setEditingPreset(null);
        setRefreshKey(k => k + 1);
    };

    const handleEditPreset = (p: Preset) => {
        setEditingPreset(p);
        setShowBuilder(true);
    };

    const handleDeletePreset = (presetId: string) => {
        // If deleted preset is currently selected, deselect it
        if (preset?.id === presetId) {
            setPreset(null);
            setUploads({});
        }
        setRefreshKey(k => k + 1);
    };

    if (showBuilder) {
        return <PresetBuilder onSave={handleBuilderDone} onCancel={() => { setShowBuilder(false); setEditingPreset(null); }} editingPreset={editingPreset} />;
    }

    return (
        <div className="flex flex-col gap-8">
            {/* Top Bar: Selector + Actions */}
            <div className="glass-card rounded-2xl p-6 lg:p-8 flex flex-col md:flex-row gap-6 items-end">
                <div className="flex-1 w-full">
                    <PresetSelector
                        selectedPreset={preset}
                        onSelect={handlePresetSelect}
                        onEdit={handleEditPreset}
                        onDelete={handleDeletePreset}
                        refreshKey={refreshKey}
                    />
                </div>
                <button
                    onClick={() => setShowBuilder(true)}
                    className="px-6 py-3 bg-zinc-800 hover:bg-zinc-700 text-zinc-200 rounded-xl transition-colors font-medium border border-zinc-700 whitespace-nowrap"
                >
                    + Tạo Preset Mới
                </button>
            </div>

            {!preset && (
                <div className="h-64 flex flex-col items-center justify-center border-2 border-dashed border-zinc-800 rounded-2xl text-zinc-500">
                    <Eye className="w-12 h-12 mb-4 opacity-50" />
                    <p className="text-lg">Vui lòng chọn một preset để bắt đầu</p>
                </div>
            )}

            {preset && (
                <>
                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                        {/* Source Blocks (Left) */}
                        <div className="lg:col-span-2 space-y-6">
                            <div className="flex items-center justify-between pb-4 border-b border-zinc-800">
                                <h2 className="text-xl font-bold flex items-center gap-2">
                                    Ảnh Nguồn Bắt Buộc
                                    <span className="bg-blue-600/20 text-blue-400 text-xs px-2 py-1 rounded-full">
                                        {preset.sourceBlocks.length}
                                    </span>
                                </h2>
                                <div className="text-sm font-medium">
                                    {Object.keys(uploads).length} / {preset.sourceBlocks.length} đã tải lên
                                </div>
                            </div>

                            {/* Prefix input */}
                            <div className="bg-white/5 border border-white/10 rounded-xl p-4">
                                <label className="block text-sm font-medium text-zinc-300 mb-2">
                                    Prefix tên file đầu ra (tuỳ chọn)
                                </label>
                                <input
                                    type="text"
                                    value={prefix}
                                    onChange={(e) => setPrefix(e.target.value)}
                                    placeholder="VD: VTS (để trống nếu không cần)"
                                    className="w-full bg-zinc-900/50 border border-zinc-700/50 rounded-xl px-4 py-3 text-zinc-100 placeholder:text-zinc-600 focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all font-mono"
                                />
                                <p className="text-xs text-zinc-500 mt-2">
                                    Ví dụ: nhập <span className="text-zinc-400">VTS</span> → file sẽ có tên <span className="text-blue-400">VTS_1080x1080.jpg</span>
                                </p>
                            </div>

                            <div className="space-y-4">
                                {preset.sourceBlocks.map(block => (
                                    <SourceUploadBlock
                                        key={block.id}
                                        block={block}
                                        fileData={uploads[block.id]}
                                        error={validation.errors[block.id]}
                                        onUpload={(file) => handleUpload(block.id, file)}
                                        onRemove={() => handleRemove(block.id)}
                                    />
                                ))}
                            </div>
                        </div>

                        {/* Config & Output List (Right) */}
                        <div className="flex flex-col gap-6">
                            <OutputSizeList preset={preset} />

                            <button
                                onClick={handleGenerate}
                                disabled={!canGenerate || isProcessing}
                                className="w-full glass-card p-6 rounded-2xl flex flex-col items-center justify-center gap-2 text-lg font-bold disabled:opacity-50 disabled:cursor-not-allowed hover:bg-blue-600/20 hover:border-blue-500/50 transition-all group border border-zinc-700"
                            >
                                {isProcessing ? (
                                    <RefreshCw className="w-8 h-8 animate-spin text-blue-400" />
                                ) : (
                                    <Download className="w-8 h-8 text-blue-400 group-hover:scale-110 transition-transform duration-300" />
                                )}
                                <span>{isProcessing ? 'Đang xuất file...' : 'Generate Full Pack (ZIP)'}</span>
                                {!canGenerate && !isProcessing && (
                                    <span className="text-xs font-normal text-red-400 text-center mt-2 max-w-[200px]">
                                        Vui lòng tải đủ ảnh đúng tỉ lệ
                                    </span>
                                )}
                            </button>
                        </div>
                    </div>
                </>
            )}
        </div>
    );
}

'use client';

import { Preset } from '../lib/types';
import { systemPresets } from '../data/systemPresets';
import { useState, useEffect, useCallback } from 'react';
import { Pencil, Trash2, Shield, User, Globe, RefreshCcw } from 'lucide-react';
import { fetchSharedPresets, deleteSharedPreset } from '../lib/sharedPresetService';

interface Props {
    selectedPreset: Preset | null;
    onSelect: (preset: Preset) => void;
    onEdit: (preset: Preset) => void;
    onDelete: (presetId: string) => void;
    refreshKey?: number; // triggers re-load
}

export default function PresetSelector({ selectedPreset, onSelect, onEdit, onDelete, refreshKey }: Props) {
    const [customPresets, setCustomPresets] = useState<Preset[]>([]);
    const [sharedPresets, setSharedPresets] = useState<Preset[]>([]);
    const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);
    const [isLoadingShared, setIsLoadingShared] = useState(false);

    // Kept for backward compatibility if any local presets exist, but we emphasize shared now
    const loadCustomPresets = useCallback(() => {
        try {
            const stored = localStorage.getItem('customPresets');
            if (stored) {
                setCustomPresets(JSON.parse(stored));
            } else {
                setCustomPresets([]);
            }
        } catch (e) { }
    }, []);

    const loadSharedPresets = useCallback(async () => {
        setIsLoadingShared(true);
        try {
            const presets = await fetchSharedPresets();
            setSharedPresets(presets);
        } catch (e) {
            console.error(e);
        } finally {
            setIsLoadingShared(false);
        }
    }, []);

    useEffect(() => {
        loadCustomPresets();
        loadSharedPresets();
    }, [loadCustomPresets, loadSharedPresets, refreshKey]);

    const handleSelect = (preset: Preset) => {
        onSelect(preset);
    };

    const handleDeleteConfirm = async (preset: Preset) => {
        try {
            if (preset.type === 'shared') {
                await deleteSharedPreset(preset.id);
                setSharedPresets(prev => prev.filter(p => p.id !== preset.id));
            } else {
                // Local custom
                const stored = localStorage.getItem('customPresets');
                const presets: Preset[] = stored ? JSON.parse(stored) : [];
                const updated = presets.filter(p => p.id !== preset.id);
                localStorage.setItem('customPresets', JSON.stringify(updated));
                setCustomPresets(updated);
            }
            setConfirmDeleteId(null);
            onDelete(preset.id);
        } catch (e) {
            alert('Lỗi khi xóa preset');
        }
    };

    const renderPresetList = (presets: Preset[], emptyMessage: string, themeColor: 'emerald' | 'purple') => {
        if (presets.length === 0) {
            return <p className="text-sm text-zinc-600 italic px-4 py-3">{emptyMessage}</p>;
        }

        const bgColorClass = themeColor === 'emerald' ? 'bg-emerald-600/15 border-emerald-500/40 text-emerald-300' : 'bg-purple-600/15 border-purple-500/40 text-purple-300';
        const colorClass = themeColor === 'emerald' ? 'text-emerald-400 hover:text-emerald-300' : 'text-purple-400 hover:text-purple-300';
        const hoverBgClass = themeColor === 'emerald' ? 'hover:bg-emerald-500/20' : 'hover:bg-purple-500/20';

        return (
            <div className="space-y-2">
                {presets.map(p => (
                    <div key={p.id} className="relative">
                        {/* Delete Confirmation Modal */}
                        {confirmDeleteId === p.id && (
                            <div className="absolute inset-0 z-20 bg-black/80 backdrop-blur-sm rounded-xl flex items-center justify-center gap-3 px-4">
                                <span className="text-sm text-zinc-300 mr-2">Xóa &ldquo;{p.name}&rdquo;?</span>
                                <button
                                    onClick={() => setConfirmDeleteId(null)}
                                    className="px-3 py-1.5 rounded-lg bg-zinc-700 hover:bg-zinc-600 text-zinc-200 text-sm font-medium transition-colors"
                                >
                                    Hủy
                                </button>
                                <button
                                    onClick={() => handleDeleteConfirm(p)}
                                    className="px-3 py-1.5 rounded-lg bg-red-600 hover:bg-red-500 text-white text-sm font-medium transition-colors"
                                >
                                    Xóa
                                </button>
                            </div>
                        )}

                        <div
                            className={`w-full text-left px-4 py-3 rounded-xl border transition-all flex items-center justify-between group ${selectedPreset?.id === p.id
                                ? bgColorClass
                                : 'bg-zinc-900/40 border-zinc-800 text-zinc-300 hover:bg-zinc-800/60 hover:border-zinc-700'
                                }`}
                        >
                            <button
                                onClick={() => handleSelect(p)}
                                className="flex items-center gap-3 flex-1 text-left"
                            >
                                <div>
                                    <span className="font-medium">{p.name}</span>
                                    {p.authorName && (
                                        <span className="ml-2 text-xs px-2 py-0.5 rounded bg-white/5 border border-white/10 text-zinc-400">
                                            bởi <strong className="text-zinc-300">{p.authorName}</strong>
                                        </span>
                                    )}
                                </div>
                                <span className="text-xs text-zinc-500">{p.outputs.length} sizes · {p.sourceBlocks.length} blocks</span>
                            </button>

                            <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                <button
                                    onClick={(e) => { e.stopPropagation(); onEdit(p); }}
                                    className={`p-2 rounded-lg ${hoverBgClass} text-zinc-400 ${colorClass} transition-colors`}
                                    title="Sửa preset"
                                >
                                    <Pencil className="w-4 h-4" />
                                </button>
                                <button
                                    onClick={(e) => { e.stopPropagation(); setConfirmDeleteId(p.id); }}
                                    className="p-2 rounded-lg hover:bg-red-500/20 text-zinc-400 hover:text-red-400 transition-colors"
                                    title="Xóa preset"
                                >
                                    <Trash2 className="w-4 h-4" />
                                </button>
                            </div>
                        </div>
                    </div>
                ))}
            </div>
        );
    };

    return (
        <div className="w-full space-y-6">
            <div>
                <label className="block text-sm font-medium text-zinc-300 mb-2">
                    Chọn Bộ kích thước (Preset)
                </label>

                {/* System Presets */}
                <div className="mb-6">
                    <div className="flex items-center gap-2 mb-2">
                        <Shield className="w-4 h-4 text-blue-400" />
                        <span className="text-xs font-semibold text-zinc-400 uppercase tracking-wider">System Presets</span>
                    </div>
                    <div className="space-y-2">
                        {systemPresets.map(p => (
                            <button
                                key={p.id}
                                onClick={() => handleSelect(p)}
                                className={`w-full text-left px-4 py-3 rounded-xl border transition-all flex items-center justify-between group ${selectedPreset?.id === p.id
                                    ? 'bg-blue-600/15 border-blue-500/40 text-blue-300'
                                    : 'bg-zinc-900/40 border-zinc-800 text-zinc-300 hover:bg-zinc-800/60 hover:border-zinc-700'
                                    }`}
                            >
                                <div className="flex items-center gap-3">
                                    <span className="font-medium">{p.name}</span>
                                    <span className="text-xs text-zinc-500">{p.outputs.length} sizes · {p.sourceBlocks.length} blocks</span>
                                </div>
                            </button>
                        ))}
                    </div>
                </div>

                {/* Shared Presets */}
                <div className="mb-6">
                    <div className="flex justify-between items-end mb-2">
                        <div className="flex items-center gap-2">
                            <Globe className="w-4 h-4 text-purple-400" />
                            <span className="text-xs font-semibold text-zinc-400 uppercase tracking-wider">Public Shared Presets</span>
                        </div>
                        <button
                            onClick={loadSharedPresets}
                            disabled={isLoadingShared}
                            className="text-xs text-zinc-500 hover:text-zinc-300 flex items-center gap-1 transition-colors"
                        >
                            <RefreshCcw className={`w-3 h-3 ${isLoadingShared ? 'animate-spin' : ''}`} />
                            Làm mới
                        </button>
                    </div>
                    {isLoadingShared && sharedPresets.length === 0 ? (
                        <div className="flex justify-center p-4">
                            <RefreshCcw className="w-5 h-5 text-purple-400 animate-spin" />
                        </div>
                    ) : (
                        renderPresetList(sharedPresets, "Chưa có preset được public. Hãy tạo một preset mới!", "purple")
                    )}
                </div>

                {/* Custom Presets (Legacy Local) */}
                {customPresets.length > 0 && (
                    <div>
                        <div className="flex items-center gap-2 mb-2">
                            <User className="w-4 h-4 text-emerald-400" />
                            <span className="text-xs font-semibold text-zinc-400 uppercase tracking-wider">Local Private Presets</span>
                        </div>
                        {renderPresetList(customPresets, "Chưa có preset tùy chỉnh nào.", "emerald")}
                    </div>
                )}
            </div>
        </div>
    );
}

'use client';

import { useState, useRef, ChangeEvent } from 'react';
import { ResizeBlock, SizePreset } from '../lib/types';
import { readImageDimensions } from '../lib/imageUtils';
import { Upload, X, Trash2, Plus, Target, AlignCenter, AlignLeft, AlignRight, Palette } from 'lucide-react';

interface Props {
    block: ResizeBlock;
    index: number;
    onChange: (id: string, updates: Partial<ResizeBlock>) => void;
    onRemove: (id: string) => void;
    isFocused?: boolean;
    presets: SizePreset[];
}

export default function ResizeBlockCard({ block, index, onChange, onRemove, isFocused = false, presets = [] }: Props) {
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [newW, setNewW] = useState('');
    const [newH, setNewH] = useState('');

    const handleFileChange = async (e: ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        try {
            const dims = await readImageDimensions(file);
            const url = URL.createObjectURL(file);

            if (block.previewUrl) URL.revokeObjectURL(block.previewUrl);

            onChange(block.id, {
                inputImage: file,
                previewUrl: url,
                originalDim: dims
            });
        } catch (err) {
            alert('Lỗi khi đọc file ảnh.');
        }
    };

    const clearFile = () => {
        if (block.previewUrl) URL.revokeObjectURL(block.previewUrl);
        if (fileInputRef.current) fileInputRef.current.value = '';
        onChange(block.id, { inputImage: undefined, previewUrl: undefined, originalDim: undefined });
    };

    const addOutput = () => {
        const w = parseInt(newW);
        const h = parseInt(newH);
        if (!w || !h) return;
        onChange(block.id, { outputs: [...block.outputs, { width: w, height: h }] });
        setNewW('');
        setNewH('');
    };

    const removeOutput = (idx: number) => {
        const newOutputs = [...block.outputs];
        newOutputs.splice(idx, 1);
        onChange(block.id, { outputs: newOutputs });
    };

    const handlePresetSelected = (e: ChangeEvent<HTMLSelectElement>) => {
        const presetId = e.target.value;
        if (!presetId) return;
        const preset = presets.find(p => p.id === presetId);
        if (preset) {
            const existing = new Set(block.outputs.map(o => `${o.width}x${o.height}`));
            const toAdd = preset.sizes.filter(s => !existing.has(`${s.width}x${s.height}`));
            onChange(block.id, { outputs: [...block.outputs, ...toAdd] });
        }
        e.target.value = ''; // Reset select after adding
    };

    return (
        <div className={`glass-card rounded-2xl p-5 relative border transition-all ${isFocused ? 'border-purple-500/50' : 'border-zinc-800/80'} group`}>
            {/* Header / ID */}
            <div className="absolute top-4 right-4 flex gap-2">
                <button onClick={(e) => { e.stopPropagation(); onRemove(block.id); }} className="p-1.5 text-zinc-600 hover:text-red-400 hover:bg-red-400/10 rounded-md transition-colors" title="Xóa Block">
                    <Trash2 className="w-4 h-4" />
                </button>
            </div>

            <div className="flex items-center gap-2 mb-4">
                <div className={`w-6 h-6 rounded-full flex items-center justify-center font-bold text-xs ${isFocused ? 'bg-purple-500/20 text-purple-400' : 'bg-zinc-800 text-zinc-400'}`}>
                    {index + 1}
                </div>
                <h3 className={`text-base font-bold ${isFocused ? 'text-zinc-100' : 'text-zinc-400'}`}>Khu vực Resize Job {isFocused && <span className="ml-2 text-xs font-normal text-purple-400 bg-purple-500/10 px-2 py-0.5 rounded border border-purple-500/20">Đang chọn</span>}</h3>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-12 gap-6">
                {/* 1. COMPACT IMAGE (left side, 3 cols) */}
                <div className="md:col-span-3 flex flex-col gap-3">
                    {!block.inputImage ? (
                        <div
                            onClick={(e) => { e.stopPropagation(); fileInputRef.current?.click(); }}
                            className="w-full aspect-square border-2 border-dashed border-zinc-700/50 hover:border-purple-500/50 transition-colors rounded-xl flex flex-col items-center justify-center gap-2 cursor-pointer text-zinc-500 hover:text-zinc-300 bg-black/20"
                        >
                            <Upload className="w-5 h-5" />
                            <span className="text-xs font-medium">Tải một ảnh</span>
                            <input ref={fileInputRef} type="file" accept="image/*" className="hidden" onChange={handleFileChange} />
                        </div>
                    ) : (
                        <div className="w-full aspect-square relative bg-black/40 border border-zinc-800 rounded-xl overflow-hidden group/img">
                            <button onClick={(e) => { e.stopPropagation(); clearFile(); }} className="absolute top-1 right-1 z-10 bg-black/60 hover:bg-red-500/80 p-1 rounded-md transition-colors opacity-0 group-hover/img:opacity-100">
                                <X className="w-3 h-3 text-white" />
                            </button>
                            <div className="w-full h-full flex items-center justify-center p-2">
                                {/* eslint-disable-next-line @next/next/no-img-element */}
                                <img src={block.previewUrl} alt="Preview" className="max-w-full max-h-full object-contain drop-shadow" />
                            </div>
                            <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-black/90 to-transparent p-2 pt-4 flex flex-col items-center pointer-events-none">
                                <span className="text-[10px] text-zinc-300 truncate w-full text-center" title={block.inputImage.name}>{block.inputImage.name}</span>
                                <span className="text-[10px] font-mono font-bold text-zinc-100">{block.originalDim?.width} × {block.originalDim?.height} px</span>
                            </div>
                        </div>
                    )}
                </div>

                {/* 2. CONFIGURATION (middle, 4 cols) */}
                <div className="md:col-span-4 flex flex-col gap-4 border-l border-zinc-800/50 pl-6">
                    <div>
                        <span className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest block mb-2">Chế Độ Resize</span>
                        <div className="space-y-2">
                            <label className={`flex items-start gap-2 cursor-pointer p-2 rounded-lg border transition-colors hover:bg-zinc-800/30 ${block.fitMode === 'cover_crop' ? 'bg-purple-600/10 border-purple-500/40' : 'bg-black/20 border-zinc-800/50'}`}>
                                <input type="radio" checked={block.fitMode === 'cover_crop'} onChange={() => onChange(block.id, { fitMode: 'cover_crop' })} className="mt-0.5 text-purple-500 bg-zinc-900 border-zinc-700" />
                                <div>
                                    <div className={`text-sm font-semibold ${block.fitMode === 'cover_crop' ? 'text-purple-300' : 'text-zinc-300'}`}>Cắt lấp đầy (Crop)</div>
                                    <div className="text-[10px] text-zinc-500">Giữ chặt tỉ lệ, mất góc</div>
                                </div>
                            </label>

                            <label className={`flex items-start gap-2 cursor-pointer p-2 rounded-lg border transition-colors hover:bg-zinc-800/30 ${block.fitMode === 'contain_with_background' ? 'bg-purple-600/10 border-purple-500/40' : 'bg-black/20 border-zinc-800/50'}`}>
                                <input type="radio" checked={block.fitMode === 'contain_with_background'} onChange={() => onChange(block.id, { fitMode: 'contain_with_background' })} className="mt-0.5 text-purple-500 bg-zinc-900 border-zinc-700" />
                                <div className="w-full">
                                    <div className={`text-sm font-semibold ${block.fitMode === 'contain_with_background' ? 'text-purple-300' : 'text-zinc-300'}`}>Vừa khung + Màu nền</div>
                                    <div className="text-[10px] text-zinc-500 mb-1">Giữ nguyên ảnh, bù nền</div>
                                    {block.fitMode === 'contain_with_background' && (
                                        <div className="flex items-center gap-1.5 bg-black/30 p-1 rounded-md mt-1" onClick={e => e.stopPropagation()}>
                                            <Palette className="w-3 h-3 text-zinc-400 ml-1" />
                                            <input type="color" value={block.bgColor} onChange={e => onChange(block.id, { bgColor: e.target.value })} className="w-4 h-4 rounded cursor-pointer p-0 border-0 bg-transparent inline-block" />
                                            <span className="text-[10px] font-mono text-zinc-400">{block.bgColor}</span>
                                        </div>
                                    )}
                                </div>
                            </label>

                            <label className={`flex items-start gap-2 cursor-pointer p-2 rounded-lg border transition-colors hover:bg-zinc-800/30 ${block.fitMode === 'contain_no_background' ? 'bg-purple-600/10 border-purple-500/40' : 'bg-black/20 border-zinc-800/50'}`}>
                                <input type="radio" checked={block.fitMode === 'contain_no_background'} onChange={() => onChange(block.id, { fitMode: 'contain_no_background' })} className="mt-0.5 text-purple-500 bg-zinc-900 border-zinc-700" />
                                <div>
                                    <div className={`text-sm font-semibold ${block.fitMode === 'contain_no_background' ? 'text-purple-300' : 'text-zinc-300'}`}>Thu nhỏ trong suốt</div>
                                    <div className="text-[10px] text-zinc-500">Nền rỗng (dành cho PNG)</div>
                                </div>
                            </label>
                        </div>
                    </div>

                    <div>
                        <span className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest block mb-2">Vị Trí (Align)</span>
                        <div className="flex bg-zinc-900 rounded-md p-1 border border-zinc-800">
                             {[
                                { id: 'left', icon: AlignLeft, label: 'Trái' },
                                { id: 'center', icon: AlignCenter, label: 'Giữa' },
                                { id: 'right', icon: AlignRight, label: 'Phải' }
                            ].map(aln => (
                                <button
                                    key={aln.id}
                                    onClick={(e) => { e.stopPropagation(); onChange(block.id, { align: aln.id as ResizeBlock['align'] }); }}
                                    className={`flex-1 flex items-center justify-center gap-1 py-1 text-[10px] font-medium rounded transition-all ${
                                        block.align === aln.id ? 'bg-zinc-700 text-white shadow-sm' : 'text-zinc-500 hover:text-zinc-300 hover:bg-zinc-800'
                                    }`}
                                >
                                    <aln.icon className="w-3 h-3" /> {aln.label}
                                </button>
                            ))}
                        </div>
                    </div>
                </div>

                {/* 3. OUTPUT SIZES (right side, 5 cols, primary focus) */}
                <div className="md:col-span-5 flex flex-col bg-black/30 border border-zinc-800/80 rounded-xl p-4">
                    <div className="flex justify-between items-center mb-4">
                        <span className="text-sm font-bold text-zinc-200">Kích Thuớc Xuất File</span>
                        <div className="flex items-center gap-2">
                             <select
                                onChange={handlePresetSelected}
                                defaultValue=""
                                className="bg-zinc-900 border border-zinc-700 text-zinc-300 text-xs rounded px-2 py-1 max-w-[140px] focus:outline-none focus:ring-1 focus:ring-purple-500 cursor-pointer appearance-none"
                            >
                                <option value="" disabled>Load từ Preset...</option>
                                {presets.map(p => (
                                    <option key={p.id} value={p.id}>{p.name} ({p.sizes.length})</option>
                                ))}
                            </select>
                            <span className="bg-zinc-800 text-zinc-300 px-2 py-0.5 rounded text-[10px] font-bold border border-zinc-700">{block.outputs.length}</span>
                        </div>
                    </div>

                    <div className="flex flex-wrap gap-2 mb-4 flex-1 content-start custom-scrollbar overflow-y-auto max-h-[160px]">
                         {block.outputs.length === 0 ? (
                            <div className="w-full flex items-center justify-center text-xs text-zinc-600 italic text-center h-[100px] border border-dashed border-zinc-800 rounded-lg">
                                Nhập kích thước bên dưới<br/>hoặc chọn preset từ dropdown
                            </div>
                        ) : (
                            block.outputs.map((out, idx) => (
                                <div key={idx} className="flex items-center bg-zinc-800/60 border border-zinc-700/80 pl-3 pr-1 py-1 rounded-full group cursor-default shadow-sm hover:border-purple-500/30 transition-colors">
                                    <span className="font-mono text-sm font-bold text-zinc-200 tracking-tight">
                                        {out.width}<span className="text-zinc-500 font-normal mx-1">×</span>{out.height}
                                    </span>
                                    <button onClick={(e) => { e.stopPropagation(); removeOutput(idx); }} className="text-zinc-500 hover:text-red-400 hover:bg-red-400/10 p-1 ml-2 rounded-full transition-colors">
                                        <X className="w-3.5 h-3.5" />
                                    </button>
                                </div>
                            ))
                        )}
                    </div>

                    {/* Manual entry row inside the outputs area */}
                    <div className="flex items-center gap-2 pt-3 border-t border-zinc-800/80" onClick={e => e.stopPropagation()}>
                        <div className="flex items-center gap-2 flex-1 bg-zinc-900 border border-zinc-700 p-1 rounded-lg focus-within:ring-1 focus-within:ring-purple-500 focus-within:border-purple-500 transition-all">
                             <input type="number" placeholder="Width" value={newW} onChange={e => setNewW(e.target.value)} onKeyDown={e => e.key === 'Enter' && addOutput()} className="w-full bg-transparent border-0 px-2 py-1 text-sm focus:ring-0 text-center font-mono text-zinc-200" />
                            <span className="text-zinc-600 text-sm">×</span>
                            <input type="number" placeholder="Height" value={newH} onChange={e => setNewH(e.target.value)} onKeyDown={e => e.key === 'Enter' && addOutput()} className="w-full bg-transparent border-0 px-2 py-1 text-sm focus:ring-0 text-center font-mono text-zinc-200" />
                        </div>
                        <button onClick={addOutput} disabled={!newW || !newH} className="p-2 bg-purple-600 hover:bg-purple-500 text-white rounded-lg disabled:opacity-50 disabled:bg-zinc-800 disabled:text-zinc-500 transition-colors shrink-0">
                            <Plus className="w-4 h-4" />
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
}

import { Preset, SourceBlock } from './types';
import { isRatioMatch, ratioKeyToNumber } from './ratioUtils';

export interface ValidationResult {
    isValid: boolean;
    errors: Record<string, string>; // blockId -> errorMessage
}

export function validateSourceUploads(
    preset: Preset,
    uploads: Record<string, { file: File; width: number; height: number }>
): ValidationResult {
    const result: ValidationResult = {
        isValid: true,
        errors: {}
    };

    preset.sourceBlocks.forEach((block: SourceBlock) => {
        const upload = uploads[block.id];

        if (block.required && !upload) {
            result.isValid = false;
            result.errors[block.id] = `Thiếu ảnh nguồn: ${block.displayName}`;
            return;
        }

        if (upload) {
            const isMatch = isRatioMatch(upload.width, upload.height, block.ratioKey, 0.02);
            if (!isMatch) {
                result.isValid = false;
                result.errors[block.id] = `Ảnh tải lên cho block ${block.displayName} không đúng tỉ lệ ${block.ratioLabel}`;
            }
        }
    });

    return result;
}

export function canGenerateFullPack(validationResult: ValidationResult, preset: Preset, uploads: Record<string, any>): boolean {
    if (!validationResult.isValid) return false;

    // Also check if all required blocks have uploads
    const missingRequired = preset.sourceBlocks.some(b => b.required && !uploads[b.id]);
    return !missingRequired;
}

export function parseResizePercentInput(input: string): number[] {
    if (!input) return [];

    const values = input.split(',')
        .map(v => parseFloat(v.trim()))
        .filter(v => !isNaN(v) && v > 0);

    return values;
}
